import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Dashboard from './pages/Dashboard';
import Reports from './pages/Reports';

export default function App() {
  return (
    <BrowserRouter>
      <Navbar />
      <Routes>
        <Route path='/' element={<Dashboard />} />
        <Route path='/reports' element={<Reports />} />
      </Routes>
    </BrowserRouter>
  );
}

import React from 'react';
import { NavLink } from 'react-router-dom';

export default function Navbar() {
  const style = ({ isActive }) => ({ textDecoration: 'none', color: isActive ? '#0f172a' : '#64748b', fontWeight: isActive ? 700 : 500 });

  return (
    <nav style={{ borderBottom: '1px solid #e2e8f0', background: '#fff' }}>
      <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '16px 24px', display: 'flex', justifyContent: 'space-between' }}>
        <h2 style={{ margin: 0 }}>SalesScope</h2>
        <div style={{ display: 'flex', gap: '18px' }}>
          <NavLink to='/' style={style}>Dashboard</NavLink>
          <NavLink to='/reports' style={style}>Reports</NavLink>
        </div>
      </div>
    </nav>
  );
}

import React from 'react';

export default function KpiCard({ label, value }) {
  return (
    <div style={{ border: '1px solid #e2e8f0', borderRadius: '14px', padding: '18px', background: '#fff' }}>
      <p style={{ margin: '0 0 8px 0', color: '#64748b' }}>{label}</p>
      <h3 style={{ margin: 0 }}>{value}</h3>
    </div>
  );
}

import React from 'react';

export default function ChartCard({ title, children }) {
  return (
    <div style={{ border: '1px solid #e2e8f0', borderRadius: '14px', padding: '18px', background: '#fff' }}>
      <h3 style={{ marginTop: 0 }}>{title}</h3>
      <div style={{ height: '160px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#64748b', background: '#f8fafc', borderRadius: '12px' }}>
        {children}
      </div>
    </div>
  );
}

import React from 'react';
import KpiCard from '../components/KpiCard';
import ChartCard from '../components/ChartCard';

export default function Dashboard() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', flexWrap: 'wrap', gap: '12px' }}>
        <div>
          <h1 style={{ marginBottom: '6px' }}>Sales Dashboard</h1>
          <p style={{ color: '#64748b' }}>Track sales performance and business KPIs.</p>
        </div>
        <input type='date' style={{ padding: '10px 12px', borderRadius: '10px', border: '1px solid #cbd5e1' }} />
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '18px', marginBottom: '24px' }}>
        <KpiCard label='Total Sales' value='$12,400' />
        <KpiCard label='Orders' value='328' />
        <KpiCard label='Profit' value='$3,280' />
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '18px' }}>
        <ChartCard title='Sales Trend'>Sales Trend Chart Placeholder</ChartCard>
        <ChartCard title='Revenue by Category'>Category Revenue Chart Placeholder</ChartCard>
      </div>
    </div>
  );
}

import React from 'react';

const reports = [
  { id: 1, report_name: 'Weekly Sales Summary', generated_at: '2026-03-20' },
  { id: 2, report_name: 'Monthly Revenue Report', generated_at: '2026-03-24' }
];

export default function Reports() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Reports</h1>
      <div style={{ display: 'grid', gap: '14px' }}>
        {reports.map(report => (
          <div key={report.id} style={{ border: '1px solid #e2e8f0', borderRadius: '12px', padding: '16px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div>
              <strong>{report.report_name}</strong>
              <p style={{ margin: '6px 0 0 0', color: '#64748b' }}>Generated on {report.generated_at}</p>
            </div>
            <button style={{ padding: '10px 14px', borderRadius: '10px', border: 'none', background: '#0f172a', color: '#fff' }}>Download</button>
          </div>
        ))}
      </div>
    </div>
  );
}

from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/api/kpis')
def get_kpis():
    return jsonify({
        'total_sales': 12400,
        'orders': 328,
        'profit': 3280
    })

@app.route('/api/reports')
def get_reports():
    return jsonify({
        'reports': [
            {'id': 1, 'report_name': 'Weekly Sales Summary', 'generated_at': '2026-03-20'},
            {'id': 2, 'report_name': 'Monthly Revenue Report', 'generated_at': '2026-03-24'}
        ]
    })

if __name__ == '__main__':
    app.run(debug=True)
